document.addEventListener('DOMContentLoaded',function(){var backToTop=document.getElementById('backToTop');var emailBtn=document.getElementById('popupEmailBtn');if(backToTop){function toggleBackTop(){if(window.scrollY>700){backToTop.classList.add('show');}else{backToTop.classList.remove('show');}}window.addEventListener('scroll',toggleBackTop);toggleBackTop();backToTop.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});}if(emailBtn){emailBtn.addEventListener('click',function(e){e.preventDefault();if(typeof elementorProFrontend !=='undefined'&&elementorProFrontend.modules&&elementorProFrontend.modules.popup){elementorProFrontend.modules.popup.showPopup({id:2650});}else{console.warn('Elementor Pro Popup is not loaded. Please check whether Popup ID 2650 is correct.');}});}});